import socket
import threading
import json
import time
import math
import random

class Player:
    def __init__(self, player_id, conn, addr):
        self.id = player_id
        self.conn = conn
        self.addr = addr
        self.x = random.uniform(0, 1000)
        self.y = random.uniform(0, 1000)
        self.z = 0
        self.health = 100
        self.alive = True
        self.rotation = 0
        self.velocity_x = 0
        self.velocity_y = 0
        self.last_update = time.time()

class GameServer:
    def __init__(self, host='0.0.0.0', port=5555):
        self.host = host
        self.port = port
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.players = {}
        self.player_id_counter = 0
        self.running = False
        self.lock = threading.Lock()
        self.tick_rate = 20
        
    def start(self):
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(100)
        self.running = True
        print(f"Game server started on {self.host}:{self.port}")
        
        threading.Thread(target=self.game_loop, daemon=True).start()
        
        while self.running:
            try:
                conn, addr = self.server_socket.accept()
                threading.Thread(target=self.handle_client, args=(conn, addr), daemon=True).start()
            except Exception as e:
                print(f"Error accepting connection: {e}")
                
    def handle_client(self, conn, addr):
        with self.lock:
            player_id = self.player_id_counter
            self.player_id_counter += 1
            player = Player(player_id, conn, addr)
            self.players[player_id] = player
            
        print(f"Player {player_id} connected from {addr}")
        
        try:
            welcome_msg = {
                'type': 'welcome',
                'player_id': player_id,
                'x': player.x,
                'y': player.y
            }
            self.send_message(conn, welcome_msg)
            
            while self.running:
                data = self.receive_message(conn)
                if not data:
                    break
                    
                self.process_player_input(player_id, data)
                
        except Exception as e:
            print(f"Error handling client {player_id}: {e}")
        finally:
            with self.lock:
                if player_id in self.players:
                    del self.players[player_id]
            try:
                conn.close()
            except:
                pass
            print(f"Player {player_id} disconnected")
            
    def process_player_input(self, player_id, data):
        with self.lock:
            if player_id not in self.players:
                return
                
            player = self.players[player_id]
            
            if data.get('type') == 'move':
                player.x = data.get('x', player.x)
                player.y = data.get('y', player.y)
                player.z = data.get('z', player.z)
                player.rotation = data.get('rotation', player.rotation)
                player.velocity_x = data.get('velocity_x', 0)
                player.velocity_y = data.get('velocity_y', 0)
                player.last_update = time.time()
                
            elif data.get('type') == 'shoot':
                target_id = data.get('target_id')
                if target_id in self.players:
                    target = self.players[target_id]
                    damage = data.get('damage', 10)
                    target.health -= damage
                    if target.health <= 0:
                        target.alive = False
                        
    def game_loop(self):
        while self.running:
            start_time = time.time()
            
            self.broadcast_game_state()
            
            elapsed = time.time() - start_time
            sleep_time = max(0, (1.0 / self.tick_rate) - elapsed)
            time.sleep(sleep_time)
            
    def broadcast_game_state(self):
        with self.lock:
            if not self.players:
                return
                
            game_state = {
                'type': 'game_state',
                'timestamp': time.time(),
                'players': []
            }
            
            for player_id, player in self.players.items():
                player_data = {
                    'id': player.id,
                    'x': player.x,
                    'y': player.y,
                    'z': player.z,
                    'rotation': player.rotation,
                    'velocity_x': player.velocity_x,
                    'velocity_y': player.velocity_y,
                    'health': player.health,
                    'alive': player.alive
                }
                game_state['players'].append(player_data)
                
            for player_id, player in list(self.players.items()):
                try:
                    self.send_message(player.conn, game_state)
                except Exception as e:
                    print(f"Error broadcasting to player {player_id}: {e}")
                    
    def send_message(self, conn, data):
        message = json.dumps(data)
        message_bytes = message.encode('utf-8')
        length = len(message_bytes)
        conn.sendall(length.to_bytes(4, byteorder='big'))
        conn.sendall(message_bytes)
        
    def receive_message(self, conn):
        length_bytes = conn.recv(4)
        if not length_bytes:
            return None
        length = int.from_bytes(length_bytes, byteorder='big')
        data = b''
        while len(data) < length:
            chunk = conn.recv(min(length - len(data), 4096))
            if not chunk:
                return None
            data += chunk
        return json.loads(data.decode('utf-8'))
        
    def stop(self):
        self.running = False
        self.server_socket.close()

class GameClient:
    def __init__(self, host='127.0.0.1', port=5555):
        self.host = host
        self.port = port
        self.socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.player_id = None
        self.running = False
        self.game_state = {}
        self.lock = threading.Lock()
        
    def connect(self):
        self.socket.connect((self.host, self.port))
        self.running = True
        
        welcome = self.receive_message()
        if welcome and welcome.get('type') == 'welcome':
            self.player_id = welcome['player_id']
            print(f"Connected as player {self.player_id}")
            
        threading.Thread(target=self.receive_loop, daemon=True).start()
        
    def receive_loop(self):
        while self.running:
            try:
                data = self.receive_message()
                if not data:
                    break
                    
                if data.get('type') == 'game_state':
                    with self.lock:
                        self.game_state = data
                        
            except Exception as e:
                print(f"Error receiving data: {e}")
                break
                
    def send_position(self, x, y, z=0, rotation=0, velocity_x=0, velocity_y=0):
        message = {
            'type': 'move',
            'x': x,
            'y': y,
            'z': z,
            'rotation': rotation,
            'velocity_x': velocity_x,
            'velocity_y': velocity_y
        }
        self.send_message(message)
        
    def send_shoot(self, target_id, damage=10):
        message = {
            'type': 'shoot',
            'target_id': target_id,
            'damage': damage
        }
        self.send_message(message)
        
    def get_visible_players(self, max_distance=100):
        with self.lock:
            if 'players' not in self.game_state:
                return []
                
            my_player = None
            for player in self.game_state['players']:
                if player['id'] == self.player_id:
                    my_player = player
                    break
                    
            if not my_player:
                return []
                
            visible = []
            for player in self.game_state['players']:
                if player['id'] == self.player_id:
                    continue
                    
                distance = math.sqrt(
                    (player['x'] - my_player['x'])**2 + 
                    (player['y'] - my_player['y'])**2
                )
                
                if distance <= max_distance:
                    visible.append({
                        'player': player,
                        'distance': distance
                    })
                    
            return visible
            
    def send_message(self, data):
        message = json.dumps(data)
        message_bytes = message.encode('utf-8')
        length = len(message_bytes)
        self.socket.sendall(length.to_bytes(4, byteorder='big'))
        self.socket.sendall(message_bytes)
        
    def receive_message(self):
        length_bytes = self.socket.recv(4)
        if not length_bytes:
            return None
        length = int.from_bytes(length_bytes, byteorder='big')
        data = b''
        while len(data) < length:
            chunk = self.socket.recv(min(length - len(data), 4096))
            if not chunk:
                return None
            data += chunk
        return json.loads(data.decode('utf-8'))
        
    def disconnect(self):
        self.running = False
        self.socket.close()

